# Inject palettes into corresponding entries
for uid, info in palettes.items():
    if uid in data['entries']:
        content = data['entries'][uid]['content']
        if '背景设定' in content:
            idx = content.rfind('背景设定')
            content = content[:idx] + info['palette'] + '\n\n' + content[idx:]
        elif '硬约束' in content:
            hc_idx = content.rfind('硬约束')
            rest = content[hc_idx:]
            if '\n背景' in rest:
                bg_idx = content.find('\n背景', hc_idx)
                content = content[:bg_idx] + info['palette'] + '\n' + content[bg_idx:]
            elif '\n与<' in rest:
                rel_idx = content.find('\n与<', hc_idx)
                content = content[:rel_idx] + info['palette'] + '\n' + content[rel_idx:]
            else:
                content += info['palette']
        else:
            content += info['palette']
        
        data['entries'][uid]['content'] = content
        print(f"✅ Injected palette into UID {uid} ({info['comment']})")
    else:
        print(f"❌ UID {uid} not found")

# Write back
with open('new_card/Metaverse-New.json', 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print("\n✅ Done! Written to Metaverse-New.json")
